Professional thermal receipt printer for the POS application.

This module preserves the existing app-facing `ReceiptPrinter` API while
switching the rendering engine to an HTML/CSS + QTextDocument thermal layout.
"""
from __future__ import annotations

import html
import math
from dataclasses import dataclass, field
from datetime import datetime
from typing import Literal

from PySide6.QtCore import QMarginsF, QSizeF
from PySide6.QtGui import QFont, QPageLayout, QPageSize, QTextDocument
from PySide6.QtPrintSupport import QPrintPreviewDialog, QPrinter, QPrinterInfo
from PySide6.QtWidgets import QWidget

from config.constants import APP_NAME


ThermalPaperWidth = Literal["58mm", "80mm"]


@dataclass(slots=True)
class ReceiptItem:
    """Normalized cart line for the receipt."""

    name: str
    qty: float
    unit: str
    price: float

    @property
    def subtotal(self) -> float:
        return self.qty * self.price


@dataclass(slots=True)
class ReceiptData:
    """Normalized payload required by the renderer."""

    store_name: str
    address: str
    phone: str
    cashier: str
    receipt_no: str
    created_at: datetime
    payment_type: str
    customer_name: str | None = None
    items: list[ReceiptItem] = field(default_factory=list)
    payment_breakdown: dict[str, float] = field(default_factory=dict)
    thank_you_text: str = "Xaridingiz uchun rahmat!"
    footer_note: str = "Yana kutib qolamiz!"
    currency: str = "so'm"

    @property
    def subtotal(self) -> float:
        return sum(item.subtotal for item in self.items)

    @property
    def total(self) -> float:
        return self.subtotal

    @property
    def debt_amount(self) -> float:
        return float(self.payment_breakdown.get("qarz", 0.0) or 0.0)

    @property
    def amount_paid(self) -> float:
        return sum(
            float(amount or 0.0)
            for payment_key, amount in self.payment_breakdown.items()
            if payment_key != "qarz"
        )

    @property
    def accounted_amount(self) -> float:
        return self.amount_paid + self.debt_amount

    @property
    def change_amount(self) -> float:
        return max(0.0, self.accounted_amount - self.total)


class ThermalReceiptEngine:
    """Reusable HTML/CSS thermal receipt renderer."""

    PAPER_WIDTH_MM = {
        "58mm": 58.0,
        "80mm": 80.0,
    }
    PAPER_NAME = {
        "58mm": "Thermal58mm",
        "80mm": "Thermal80mm",
    }
    PAGE_MARGINS_MM = QMarginsF(1.5, 1.5, 1.5, 2.5)
    MIN_PAGE_HEIGHT_MM = 75.0
    MAX_PAGE_HEIGHT_MM = 800.0
    PROVISIONAL_HEIGHT_MM = 260.0
    DEFAULT_DPI = 203

    def __init__(self, paper_width: ThermalPaperWidth) -> None:
        if paper_width not in self.PAPER_WIDTH_MM:
            raise ValueError(f"Unsupported paper width: {paper_width}")
        self.paper_width = paper_width

    def generate_html(self, receipt: ReceiptData) -> str:
        """Build the thermal receipt markup."""
        width_mm = self.PAPER_WIDTH_MM[self.paper_width]
        is_narrow = width_mm <= 58.0
        base_font = 8 if is_narrow else 9
        title_font = 11 if is_narrow else 13
        total_font = 10 if is_narrow else 12
        separator_line = "-" * (32 if is_narrow else 42)

        item_rows = "".join(self._build_item_row(item) for item in receipt.items)
        if not item_rows:
            item_rows = (
                '<tr><td colspan="4" class="empty-row">Mahsulot mavjud emas</td></tr>'
            )

        address_html = (
            f'<p class="meta muted">{self._escape(receipt.address)}</p>'
            if receipt.address
            else ""
        )
        phone_html = (
            f'<p class="meta muted">Tel: {self._escape(receipt.phone)}</p>'
            if receipt.phone
            else ""
        )
        customer_html = ""
        if receipt.customer_name:
            customer_html = f"""
      <div class="summary-row">
        <span class="summary-label">Mijoz</span>
        <span class="summary-value">{self._escape(receipt.customer_name)}</span>
      </div>"""

        payment_rows = self._build_payment_rows(receipt)
        created_at = receipt.created_at.strftime("%d.%m.%Y %H:%M:%S")

        return f"""<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <style>
    @page {{
      margin: 0;
      size: auto;
    }}

    html, body {{
      margin: 0;
      padding: 0;
      background: #ffffff;
      color: #111111;
      font-family: "Consolas", "Courier New", monospace;
      font-size: {base_font}pt;
      line-height: 1.30;
    }}

    .receipt {{
      width: 100%;
      box-sizing: border-box;
    }}

    .center {{
      text-align: center;
    }}

    .store-title {{
      margin: 0 0 1.5mm 0;
      font-size: {title_font}pt;
      font-weight: 700;
      letter-spacing: 0.5px;
      text-transform: uppercase;
    }}

    .meta,
    .footer-text {{
      margin: 0.4mm 0;
    }}

    .muted {{
      color: #333333;
    }}

    .separator {{
      margin: 2.2mm 0 2mm 0;
      white-space: nowrap;
      overflow: hidden;
      color: #111111;
    }}

    table {{
      width: 100%;
      border-collapse: collapse;
      table-layout: fixed;
    }}

    .items th,
    .items td {{
      padding: 1mm 0;
      vertical-align: top;
      word-wrap: break-word;
    }}

    .items th {{
      font-weight: 700;
      border-bottom: 0.35mm dashed #111111;
      padding-bottom: 1.2mm;
    }}

    .items .col-name {{
      width: 46%;
      text-align: left;
      padding-right: 1.2mm;
    }}

    .items .col-qty {{
      width: 16%;
      text-align: right;
      padding-right: 1mm;
    }}

    .items .col-price {{
      width: 18%;
      text-align: right;
      padding-right: 1mm;
    }}

    .items .col-subtotal {{
      width: 20%;
      text-align: right;
    }}

    .summary {{
      margin-top: 0.8mm;
    }}

    .summary-row {{
      width: 100%;
      margin: 0.7mm 0;
      overflow: hidden;
    }}

    .summary-label {{
      float: left;
      width: 52%;
    }}

    .summary-value {{
      float: right;
      width: 48%;
      text-align: right;
    }}

    .summary-row::after {{
      content: "";
      display: block;
      clear: both;
    }}

    .total-box {{
      margin-top: 1.5mm;
      padding-top: 1.4mm;
      border-top: 0.45mm solid #111111;
      font-size: {total_font}pt;
      font-weight: 700;
    }}

    .empty-row {{
      text-align: center;
      padding: 2mm 0;
      color: #444444;
    }}

    .footer {{
      margin-top: 1.4mm;
    }}
  </style>
</head>
<body>
  <div class="receipt">
    <div class="center">
      <div class="store-title">{self._escape(receipt.store_name)}</div>
      {address_html}
      {phone_html}
    </div>

    <div class="separator">{separator_line}</div>

    <div class="summary">
      <div class="summary-row">
        <span class="summary-label">Chek raqami</span>
        <span class="summary-value">{self._escape(receipt.receipt_no)}</span>
      </div>
      <div class="summary-row">
        <span class="summary-label">Sana</span>
        <span class="summary-value">{self._escape(created_at)}</span>
      </div>
      <div class="summary-row">
        <span class="summary-label">Kassir</span>
        <span class="summary-value">{self._escape(receipt.cashier)}</span>
      </div>
      {customer_html}
      <div class="summary-row">
        <span class="summary-label">To'lov turi</span>
        <span class="summary-value">{self._escape(receipt.payment_type)}</span>
      </div>
    </div>

    <div class="separator">{separator_line}</div>

    <table class="items">
      <thead>
        <tr>
          <th class="col-name">Mahsulot</th>
          <th class="col-qty">Soni</th>
          <th class="col-price">Narx</th>
          <th class="col-subtotal">Jami</th>
        </tr>
      </thead>
      <tbody>
        {item_rows}
      </tbody>
    </table>

    <div class="separator">{separator_line}</div>

    <div class="summary">
      {payment_rows}
      <div class="summary-row total-box">
        <span class="summary-label">UMUMIY</span>
        <span class="summary-value">{self._money(receipt.total, receipt.currency)}</span>
      </div>
      <div class="summary-row">
        <span class="summary-label">To'langan</span>
        <span class="summary-value">{self._money(receipt.amount_paid, receipt.currency)}</span>
      </div>
      {self._build_debt_row(receipt)}
      <div class="summary-row">
        <span class="summary-label">Qaytim</span>
        <span class="summary-value">{self._money(receipt.change_amount, receipt.currency)}</span>
      </div>
    </div>

    <div class="separator">{separator_line}</div>

    <div class="center footer">
      <p class="footer-text">{self._escape(receipt.thank_you_text)}</p>
      <p class="footer-text muted">{self._escape(receipt.footer_note)}</p>
    </div>
  </div>
</body>
</html>
"""

    def preview_receipt(self, receipt: ReceiptData, parent: QWidget | None = None) -> None:
        """Show the thermal receipt in QPrintPreviewDialog."""
        printer = self._create_printer()
        preview = QPrintPreviewDialog(printer, parent)
        preview.setWindowTitle(f"Chek Preview ({self.paper_width})")
        preview.resize(950, 720)
        preview.paintRequested.connect(lambda preview_printer: self._render_receipt(receipt, preview_printer))
        preview.exec()

    def print_receipt(self, receipt: ReceiptData) -> None:
        """Send the thermal receipt directly to the default printer."""
        printer = self._create_printer()
        self._render_receipt(receipt, printer)

    def _build_item_row(self, item: ReceiptItem) -> str:
        return f"""
        <tr>
          <td class="col-name">{self._escape(item.name)}</td>
          <td class="col-qty">{self._escape(self._format_qty(item.qty, item.unit))}</td>
          <td class="col-price">{self._escape(self._money(item.price, None))}</td>
          <td class="col-subtotal">{self._escape(self._money(item.subtotal, None))}</td>
        </tr>
        """

    def _build_payment_rows(self, receipt: ReceiptData) -> str:
        rows = []
        labels = {
            "naqd": "Naqd",
            "karta": "Karta",
            "click": "Click",
            "qarz": "Qarz",
        }
        for payment_key in ("naqd", "karta", "click"):
            amount = float(receipt.payment_breakdown.get(payment_key, 0.0) or 0.0)
            if amount <= 0:
                continue
            rows.append(
                f"""
      <div class="summary-row">
        <span class="summary-label">{labels[payment_key]}</span>
        <span class="summary-value">{self._money(amount, receipt.currency)}</span>
      </div>"""
            )
        return "".join(rows)

    def _build_debt_row(self, receipt: ReceiptData) -> str:
        if receipt.debt_amount <= 0:
            return ""
        return f"""
      <div class="summary-row">
        <span class="summary-label">Qarzga yozildi</span>
        <span class="summary-value">{self._money(receipt.debt_amount, receipt.currency)}</span>
      </div>"""

    def _render_receipt(self, receipt: ReceiptData, printer: QPrinter) -> None:
        """Measure the document first, then print with exact thermal height."""
        html_content = self.generate_html(receipt)
        width_mm = self.PAPER_WIDTH_MM[self.paper_width]

        self._configure_printer_page(printer, width_mm, self.PROVISIONAL_HEIGHT_MM)
        document = self._create_document(html_content, printer)

        final_height_mm = self._calculate_content_height_mm(document, printer)
        final_height_mm = max(self.MIN_PAGE_HEIGHT_MM, min(final_height_mm, self.MAX_PAGE_HEIGHT_MM))

        self._configure_printer_page(printer, width_mm, final_height_mm)
        final_document = self._create_document(html_content, printer)
        final_document.print(printer)

    def _create_printer(self) -> QPrinter:
        """Create a native high-resolution printer bound to the default device."""
        printer = QPrinter(QPrinter.PrinterMode.HighResolution)
        printer.setOutputFormat(QPrinter.OutputFormat.NativeFormat)
        printer.setFullPage(False)
        printer.setResolution(self.DEFAULT_DPI)

        default_printer = QPrinterInfo.defaultPrinter()
        if not default_printer.isNull():
            printer.setPrinterName(default_printer.printerName())
        return printer

    def _configure_printer_page(self, printer: QPrinter, width_mm: float, height_mm: float) -> None:
        """Apply a custom thermal page size and safe margins."""
        page_size = QPageSize(
            QSizeF(width_mm, height_mm),
            QPageSize.Unit.Millimeter,
            self.PAPER_NAME[self.paper_width],
        )
        printer.setPageSize(page_size)
        printer.setPageMargins(self.PAGE_MARGINS_MM, QPageLayout.Unit.Millimeter)

        page_layout = QPageLayout(
            page_size,
            QPageLayout.Orientation.Portrait,
            self.PAGE_MARGINS_MM,
            QPageLayout.Unit.Millimeter,
        )
        printer.setPageLayout(page_layout)

    def _create_document(self, html_content: str, printer: QPrinter) -> QTextDocument:
        """Create a QTextDocument sized to the printer's paintable width."""
        document = QTextDocument()
        document.setDefaultFont(QFont("Consolas", 9))
        document.setDocumentMargin(0)
        document.setHtml(html_content)

        printable_rect = printer.pageLayout().paintRectPixels(printer.resolution())
        document.setPageSize(QSizeF(float(printable_rect.width()), 100000.0))
        return document

    def _calculate_content_height_mm(self, document: QTextDocument, printer: QPrinter) -> float:
        """Convert rendered document height into millimeters."""
        content_height_px = document.size().height()
        pixels_to_mm = 25.4 / float(printer.resolution())
        content_height_mm = content_height_px * pixels_to_mm
        return content_height_mm + self.PAGE_MARGINS_MM.top() + self.PAGE_MARGINS_MM.bottom() + 5.0

    @staticmethod
    def _format_qty(qty: float, unit: str) -> str:
        unit_name = (unit or "").strip()
        unit_lower = unit_name.lower()
        if unit_lower in {"dona", "ta", "don", "pcs", "piece"}:
            return f"{int(round(qty))} {unit_name}".strip()
        if math.isclose(qty, round(qty), abs_tol=1e-9):
            return f"{int(round(qty))} {unit_name}".strip()
        return f"{qty:.2f}".rstrip("0").rstrip(".") + (f" {unit_name}" if unit_name else "")

    @staticmethod
    def _money(amount: float, currency: str | None) -> str:
        suffix = f" {currency}" if currency else ""
        return f"{float(amount):,.0f}{suffix}"

    @staticmethod
    def _escape(value: object) -> str:
        return html.escape(str(value))


class ReceiptPrinter:
    """App-facing adapter for the thermal receipt engine."""

    DEFAULT_PAPER_WIDTH: ThermalPaperWidth = "80mm"
    STORE_NAME = APP_NAME.upper()
    STORE_ADDRESS = ""
    STORE_PHONE = ""

    @staticmethod
    def is_printer_available() -> bool:
        try:
            return not QPrinterInfo.defaultPrinter().isNull()
        except Exception:
            return False

    @classmethod
    def preview_receipt(
        cls,
        parent,
        cart_items,
        payment_breakdown,
        cashier_name="Admin",
        customer_name=None,
    ):
        """Open preview using the current cart without saving the sale."""
        if not cart_items:
            return False, "Savat bo'sh"

        try:
            receipt = cls._build_receipt_data(
                sale=None,
                cart_items=cart_items,
                payment_breakdown=payment_breakdown,
                cashier_name=cashier_name,
                customer_name=customer_name,
            )
            cls._get_engine().preview_receipt(receipt, parent)
            return True, "Chek preview ochildi"
        except Exception as exc:
            return False, f"Preview xatosi: {str(exc)}"

    @classmethod
    def print_receipt(
        cls,
        sale,
        cart_items,
        payment_breakdown,
        cashier_name="Admin",
        customer_name=None,
    ):
        """Print the thermal receipt directly to the default printer."""
        if not cart_items:
            return False, "Savat bo'sh"
        if not cls.is_printer_available():
            return False, "Printer topilmadi"

        try:
            receipt = cls._build_receipt_data(
                sale=sale,
                cart_items=cart_items,
                payment_breakdown=payment_breakdown,
                cashier_name=cashier_name,
                customer_name=customer_name,
            )
            cls._get_engine().print_receipt(receipt)
            return True, "Thermal chek printerga yuborildi"
        except Exception as exc:
            return False, f"Printer xatosi: {str(exc)}"

    @classmethod
    def _get_engine(cls) -> ThermalReceiptEngine:
        return ThermalReceiptEngine(cls._detect_paper_width())

    @classmethod
    def _detect_paper_width(cls) -> ThermalPaperWidth:
        """Best-effort width detection from the default printer name."""
        try:
            printer_info = QPrinterInfo.defaultPrinter()
            if printer_info.isNull():
                return cls.DEFAULT_PAPER_WIDTH

            printer_name = printer_info.printerName().lower()
            if "58" in printer_name or "pos58" in printer_name:
                return "58mm"
            if "80" in printer_name or "pos80" in printer_name or "thermal" in printer_name:
                return "80mm"
        except Exception:
            pass
        return cls.DEFAULT_PAPER_WIDTH

    @classmethod
    def _build_receipt_data(
        cls,
        sale,
        cart_items,
        payment_breakdown,
        cashier_name,
        customer_name=None,
    ) -> ReceiptData:
        receipt_no = cls._build_receipt_number(sale)
        created_at = getattr(sale, "sale_date", None) or datetime.now()
        normalized_items = []

        for item in cart_items or []:
            product = item["product"]
            normalized_items.append(
                ReceiptItem(
                    name=str(getattr(product, "name", "")),
                    qty=float(item.get("quantity", 0) or 0),
                    unit=str(getattr(product, "unit", "") or ""),
                    price=float(item.get("price", 0) or 0),
                )
            )

        return ReceiptData(
            store_name=cls.STORE_NAME,
            address=cls.STORE_ADDRESS,
            phone=cls.STORE_PHONE,
            cashier=str(cashier_name or "Admin"),
            receipt_no=receipt_no,
            created_at=created_at,
            payment_type=cls._build_payment_type(payment_breakdown),
            customer_name=customer_name,
            items=normalized_items,
            payment_breakdown=dict(payment_breakdown or {}),
        )

    @staticmethod
    def _build_receipt_number(sale) -> str:
        sale_id = getattr(sale, "id", None)
        if sale_id is not None:
            return str(sale_id)
        return f"PREVIEW-{datetime.now():%H%M%S}"

    @staticmethod
    def _build_payment_type(payment_breakdown) -> str:
        labels = {
            "naqd": "Naqd",
            "karta": "Karta",
            "click": "Click",
            "qarz": "Qarz",
        }
        parts = [
            labels[key]
            for key in ("naqd", "karta", "click", "qarz")
            if float((payment_breakdown or {}).get(key, 0) or 0) > 0
        ]
        if not parts:
            return "Noma'lum"
        if len(parts) == 1:
            return parts[0]
        return " / ".join(parts)
